func:
// 多标签订阅：构造 nodeId 数组，修改为实际 OPC-UA 节点 ID
msg.topic = "multiple";
msg.payload = [
  { nodeId: "ns=2;s=Temperature" },
  { nodeId: "ns=2;s=Humidity" },
  { nodeId: "ns=2;s=ProductionCount" }
];
return msg;

// wire[0] 收到订阅变更数据
var dv = msg.payload;

// 提取实际值
var rawValue = (dv && dv.value) ? dv.value.value : null;
if (rawValue === null || rawValue === undefined) return null;

// 质量：statusCode.value === 0 为 Good
var quality = (dv.statusCode && dv.statusCode.value === 0) ? "Good" : "Bad";
if (quality !== "Good") return null;  // Bad 质量丢弃，按需改为告警

// nodeId → UNS topic 路径 + 字段名映射表
// 修改为实际的 nodeId 和 UNS 路径
var topicMap = {
  "ns=2;s=Temperature":     { topic: "Plant/Line1/Metric/Temperature",    field: "temperature" },
  "ns=2;s=Humidity":        { topic: "Plant/Line1/Metric/Humidity",        field: "humidity" },
  "ns=2;s=ProductionCount": { topic: "Plant/Line1/Metric/ProductionCount", field: "value" }
};

var mapping = topicMap[msg.topic];
if (!mapping) return null;  // 未映射的标签忽略

msg.topic   = mapping.topic;
msg.payload = JSON.stringify({ [mapping.field]: rawValue });
return msg;
